
(function () {
  window.Prism = window.Prism || {};
  window.Prism.manual = true;

  function qsa(sel, ctx) {
    return Array.prototype.slice.call((ctx || document).querySelectorAll(sel));
  }

  function getLineCount(text) {
    if (!text) return 1;
    var normalized = text.replace(/\n$/, '');
    var lines = normalized.split('\n').length;
    return Math.max(lines, 1);
  }

  function addLineNumbers(pre) {
    if (!pre.classList.contains('line-numbers')) return;
    if (pre.querySelector('.line-numbers-rows')) return;
    var code = pre.querySelector('code');
    if (!code) return;
    var rows = document.createElement('span');
    rows.className = 'line-numbers-rows';
    rows.setAttribute('aria-hidden', 'true');
    var count = getLineCount(code.textContent || '');
    var frag = document.createDocumentFragment();
    for (var i = 0; i < count; i++) {
      frag.appendChild(document.createElement('span'));
    }
    rows.appendChild(frag);
    pre.appendChild(rows);
  }

  function makeButton(text, handler) {
    var btn = document.createElement('button');
    btn.type = 'button';
    btn.textContent = text;
    btn.addEventListener('click', handler);
    return btn;
  }

  function wrapCodeBlock(pre) {
    if (pre.parentNode && pre.parentNode.classList && pre.parentNode.classList.contains('code-toolbar')) {
      addLineNumbers(pre);
      return;
    }
    var lang = (pre.getAttribute('class') || '').match(/language-([a-z0-9_-]+)/i);
    var langName = pre.getAttribute('data-lang-label') || (lang ? lang[1].toUpperCase() : 'CODE');

    var wrapper = document.createElement('div');
    wrapper.className = 'code-toolbar';
    if ((lang && /bash|shell|powershell/i.test(lang[1])) || /PowerShell|CMD/i.test(langName)) {
      wrapper.className += ' shell-window';
    }

    var toolbar = document.createElement('div');
    toolbar.className = 'toolbar';

    var left = document.createElement('div');
    left.className = 'toolbar-left';
    var dots = document.createElement('div');
    dots.className = 'window-dots';
    dots.innerHTML = '<span></span><span></span><span></span>';
    var label = document.createElement('div');
    label.className = 'label';
    label.textContent = langName;
    left.appendChild(dots);
    left.appendChild(label);

    var right = document.createElement('div');
    right.className = 'toolbar-right';
    var code = pre.querySelector('code');
    right.appendChild(makeButton('Copy', function () {
      var text = code ? code.textContent : pre.textContent;
      if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).then(function () {
          this.textContent = 'Copied';
          var self = this; setTimeout(function(){ self.textContent = 'Copy'; }, 1200);
        }.bind(this));
      } else {
        var ta = document.createElement('textarea');
        ta.value = text;
        document.body.appendChild(ta);
        ta.select();
        try { document.execCommand('copy'); } catch (e) {}
        document.body.removeChild(ta);
      }
    }));
    right.appendChild(makeButton('Print', function () {
      var win = window.open('', '_blank', 'width=900,height=700');
      if (!win) return;
      var text = code ? code.textContent : pre.textContent;
      var escaped = text
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
      var labelText = langName.replace(/</g, '&lt;').replace(/>/g, '&gt;');
      win.document.write('<!doctype html><html><head><title>' + labelText + '</title><style>body{font-family:Consolas,monospace;padding:24px;}pre{white-space:pre-wrap;border:1px solid #999;padding:16px;}</style></head><body><h1>' + labelText + '</h1><pre>' + escaped + '</pre></body></html>');
      win.document.close();
      win.focus();
      setTimeout(function(){ win.print(); }, 150);
    }));

    toolbar.appendChild(left);
    toolbar.appendChild(right);

    pre.parentNode.insertBefore(wrapper, pre);
    wrapper.appendChild(toolbar);
    wrapper.appendChild(pre);

    addLineNumbers(pre);
  }

  document.addEventListener('DOMContentLoaded', function () {
    qsa('pre[class*="language-"]').forEach(wrapCodeBlock);
  });
}());
